#: Mapping of the public ``process_priority`` values accepted by
#: :class:`Editor` to the ``niceness`` value used by
#: :func:`os.setpriority` on Unix-like systems.
_UNIX_PRIORITIES = {
    "low": 19,
    "below_normal": 10,
    "normal": 0,
    "above_normal": -10,
    "high": -20,
}

#: Mapping of the public ``process_priority`` values accepted by
#: :class:`Editor` to the ``dwPriorityClass`` value used by the Windows
#: ``SetPriorityClass`` API.
_WIN_PRIORITIES = {
    "low": 0x00000040,  # IDLE_PRIORITY_CLASS
    "below_normal": 0x00004000,  # BELOW_NORMAL_PRIORITY_CLASS
    "normal": 0x00000020,  # NORMAL_PRIORITY_CLASS
    "above_normal": 0x00008000,  # ABOVE_NORMAL_PRIORITY_CLASS
    "high": 0x00000080,  # HIGH_PRIORITY_CLASS
}


def _set_process_priority(pid: int, priority: str | None) -> None:
    """Best-effort attempt to set the CPU priority of the process
    identified by ``pid``.  Invalid ``priority`` values, unsupported
    platforms, and any failure while applying the priority are silently
    ignored so that editing can proceed regardless.
    """
    if priority is None:
        return

    if WIN:
        priority_class = _WIN_PRIORITIES.get(priority)

        if priority_class is None:
            return

        try:
            import ctypes

            PROCESS_SET_INFORMATION = 0x0200
            handle = ctypes.windll.kernel32.OpenProcess(  # type: ignore[attr-defined]
                PROCESS_SET_INFORMATION, False, pid
            )

            if not handle:
                return

            try:
                ctypes.windll.kernel32.SetPriorityClass(  # type: ignore[attr-defined]
                    handle, priority_class
                )
            finally:
                ctypes.windll.kernel32.CloseHandle(handle)  # type: ignore[attr-defined]
        except Exception:
            pass
    else:
        niceness = _UNIX_PRIORITIES.get(priority)

        if niceness is None:
            return

        try:
            os.setpriority(os.PRIO_PROCESS, pid, niceness)
        except Exception:
            pass


